import { useEffect, useState } from "react";
import axios from "axios";
import { createComplexShape } from "../api/complexShapeApi.ts";

function ComplexShapeForm() {
  const [shapes, setShapes] = useState<any[]>([]);

  const [form, setForm] = useState({
    label: "",
    shape1Id: 0,
    shape2Id: 0,
    operation: "ADD",
    offset: 0
  });

  useEffect(() => {
    axios.get("http://localhost:8080/api/shapes")
      .then(res => setShapes(res.data));
  }, []);

  const submit = async () => {
    await createComplexShape(form);
    alert("Created!");
  };

  return (
    <div>
      <h2>Create Complex Shape</h2>

      <input
        placeholder="Label"
        onChange={e => setForm({ ...form, label: e.target.value })}
      />

      <select onChange={e => setForm({ ...form, shape1Id: Number(e.target.value) })}>
        {shapes.map(s => (
          <option value={s.id}>{s.label}</option>
        ))}
      </select>

      <select onChange={e => setForm({ ...form, shape2Id: Number(e.target.value) })}>
        {shapes.map(s => (
          <option value={s.id}>{s.label}</option>
        ))}
      </select>

      <select onChange={e => setForm({ ...form, operation: e.target.value })}>
        <option value="ADD">Add</option>
        <option value="SUBTRACT">Subtract</option>
        <option value="INTERSECT">Intersect</option>
      </select>

      <input
        type="number"
        min={0}
        max={5}
        onChange={e => setForm({ ...form, offset: Number(e.target.value) })}
      />

      <button onClick={submit}>Create</button>
    </div>
  );
}

export default ComplexShapeForm;
